# ENV
env_path=BASE+\"/.env\"
if os.path.exists(env_path):
    for line in open(env_path):
        line=line.strip()
        if line and not line.startswith(\"#\") and \"=\" in line:
            d[\"env\"].append(line.split(\"=\")[0])

# CODE FILES
for f in [\"telegram_daemon.py\",\"task_worker.py\",\"core/ai_router.py\",\"core/stt_engine.py\",\"core/reply_sender.py\",\"core/pin_manager.py\",\"memory_api_server.py\",\"google_io.py\"]:
    p=BASE+\"/\"+f
    d[\"files\"][f]=open(p).read() if os.path.exists(p) else \"NOT_FOUND\"

# TASKS
db_path=BASE+\"/data/core.db\"
if os.path.exists(db_path):
    conn=sqlite3.connect(db_path)
    conn.row_factory=sqlite3.Row
    try:
        rows=conn.execute(\"SELECT t.id,t.chat_id,t.input_type,t.raw_input,t.state,t.result,t.error_message,t.created_at,t.updated_at,GROUP_CONCAT(h.action,\\\" | \\\") as history FROM tasks t LEFT JOIN task_history h ON h.task_id=t.id GROUP BY t.id ORDER BY t.created_at DESC LIMIT 300\").fetchall()
        for r in rows: d[\"tasks\"].append(dict(r))
    except Exception as e: d[\"tasks\"]=[{\"error\":str(e)}]
    finally: conn.close()

# MEMORY DB
mem_path=BASE+\"/data/memory.db\"
if os.path.exists(mem_path):
    conn=sqlite3.connect(mem_path)
    conn.row_factory=sqlite3.Row
    try:
        rows=conn.execute(\"SELECT * FROM memory ORDER BY timestamp DESC LIMIT 1000\").fetchall()
        for r in rows: d[\"memory_data\"].append(dict(r))
    except Exception as e: d[\"memory_data\"]=[{\"error\":str(e)}]
    finally: conn.close()

# LOGS
for log in [\"task_worker.log\",\"ai_router.log\",\"telegram_daemon.log\"]:
    p=BASE+\"/logs/\"+log
    d[\"logs\"][log]=\"\".join(open(p).readlines()[-500:]) if os.path.exists(p) else \"NOT_FOUND\"

# MEMORY FILES
for jsonl in glob.glob(BASE+\"/data/memory_files/**/*.jsonl\",recursive=True):
    key=jsonl.replace(BASE,\"\")
    try: d[\"memory_files_data\"][key]=\"\".join(open(jsonl).readlines()[-200:])
    except: pass

# DOMAIN FOLDERS
for folder in [\"CLIENTS\",\"ESTIMATES\",\"PROJECTS\",\"STROYKA\",\"TEHNADZOR\",\"NEURON_SOFT_VPN\",\"DEVOPS_AUTOMATION\",\"ADS_MARKETING\",\"VIDEO_CONTENT\",\"DOCS_PDF_DWG\",\"TABLES\",\"CRM_LEADS\",\"telegram\",\"tasks\",\"LOGS\",\"AUTO\",\"TEXTS\"]:
    p=BASE+\"/data/memory/\"+folder
    if os.path.exists(p):
        files=os.listdir(p)
        if files: d[\"memory_files_data\"][\"memory/\"+folder]=str(files)

out=json.dumps(d,ensure_ascii=False,default=str)
open(OUT,\"w\").write(out)
print(\"OK size=\"+str(len(out))+\" path=\"+OUT)
"'
